import{_ as s,o as a,c as n,aw as e}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"Sponsored Batch Transactions","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Sponsored Batch Transactions | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"ev-reth/features/sponsored-transactions.md","filePath":"ev-reth/features/sponsored-transactions.md","lastUpdated":1779882971000}');const t=s({name:"ev-reth/features/sponsored-transactions.md"},[["render",function(s,o,t,l,p,c){return a(),n("div",null,[...o[0]||(o[0]=[e('<h1 id="sponsored-batch-transactions" tabindex="-1">Sponsored Batch Transactions <a class="header-anchor" href="#sponsored-batch-transactions" aria-label="Permalink to &quot;Sponsored Batch Transactions&quot;">​</a></h1><p>ev-reth supports an EIP-2718 transaction type, <code>0x76</code>, for application-sponsored gas and atomic batches of EVM operations.</p><p>Use this transaction type when an application wants users to submit intents without holding the native gas token, or when a product flow needs several calls to succeed or fail together.</p><h2 id="what-it-adds" tabindex="-1">What It Adds <a class="header-anchor" href="#what-it-adds" aria-label="Permalink to &quot;What It Adds&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th></tr></thead><tbody><tr><td>Gas sponsorship</td><td>A sponsor account can pay gas for a transaction signed by another account</td></tr><tr><td>Batch calls</td><td>One transaction can execute multiple <code>Call</code> operations</td></tr><tr><td>Atomic execution</td><td>If any call reverts, the whole transaction reverts</td></tr><tr><td>Standard submission</td><td>Signed transactions are submitted through <code>eth_sendRawTransaction</code></td></tr><tr><td>RPC visibility</td><td>Sponsored transactions expose a <code>feePayer</code> field in transaction and receipt responses</td></tr></tbody></table><p>Regular Ethereum transactions still work. Use type <code>0x76</code> only for sponsored or batched flows.</p><h2 id="transaction-model" tabindex="-1">Transaction Model <a class="header-anchor" href="#transaction-model" aria-label="Permalink to &quot;Transaction Model&quot;">​</a></h2><p>An EvNode transaction replaces the standard single <code>to</code>, <code>value</code>, and <code>input</code> fields with a list of calls:</p><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> Call</span><span style="color:#767676;"> =</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">  to</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">Address</span><span style="color:#767676;"> | </span><span style="color:#B8A6FF;">null</span></span>\n<span class="line"><span style="color:#DBD7CA;">  value</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">bigint</span></span>\n<span class="line"><span style="color:#DBD7CA;">  data</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">Hex</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><p>The transaction also keeps EIP-1559-style fee fields:</p><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> EvNodeTransaction</span><span style="color:#767676;"> =</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">  chainId</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">bigint</span></span>\n<span class="line"><span style="color:#DBD7CA;">  nonce</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">bigint</span></span>\n<span class="line"><span style="color:#DBD7CA;">  maxPriorityFeePerGas</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">bigint</span></span>\n<span class="line"><span style="color:#DBD7CA;">  maxFeePerGas</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">bigint</span></span>\n<span class="line"><span style="color:#DBD7CA;">  gasLimit</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">bigint</span></span>\n<span class="line"><span style="color:#DBD7CA;">  calls</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">Call</span><span style="color:#767676;">[]</span></span>\n<span class="line"><span style="color:#DBD7CA;">  accessList</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">AccessList</span></span>\n<span class="line"><span style="color:#DBD7CA;">  feePayerSignature</span><span style="color:#888888;">?</span><span style="color:#767676;">: </span><span style="color:#CDA4EB;">Signature</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><p>The executor is the account that signs the transaction intent. The executor remains the transaction <code>from</code> address and is visible to contracts as <code>tx.origin</code>.</p><p>The sponsor is optional. When a sponsor signs the transaction, ev-reth charges gas to the sponsor instead of the executor. Value transfers still come from the executor.</p><h2 id="batch-calls" tabindex="-1">Batch Calls <a class="header-anchor" href="#batch-calls" aria-label="Permalink to &quot;Batch Calls&quot;">​</a></h2><p>Each call contains:</p><ul><li><code>to</code>: target contract or account. Use <code>null</code> for contract creation.</li><li><code>value</code>: native token value sent with that call.</li><li><code>data</code>: calldata or contract creation bytecode.</li></ul><p>Rules:</p><ul><li><code>calls</code> must contain at least one item.</li><li>Calls execute in order.</li><li>Only the first call may be a contract creation (<code>to: null</code>).</li><li>If any call fails, all state changes from earlier calls in the same transaction are reverted.</li></ul><p>Example batch:</p><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">await</span><span style="color:#DBD7CA;"> evnode</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">send</span><span style="color:#767676;">({</span></span>\n<span class="line"><span style="color:#94EEFF;">  calls</span><span style="color:#767676;">: [</span></span>\n<span class="line"><span style="color:#767676;">    { </span><span style="color:#94EEFF;">to</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">token</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">value</span><span style="color:#767676;">: </span><span style="color:#FFECB6;">0</span><span style="color:#B8A6FF;">n</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">data</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">approveData</span><span style="color:#767676;"> },</span></span>\n<span class="line"><span style="color:#767676;">    { </span><span style="color:#94EEFF;">to</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">router</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">value</span><span style="color:#767676;">: </span><span style="color:#FFECB6;">0</span><span style="color:#B8A6FF;">n</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">data</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">swapData</span><span style="color:#767676;"> },</span></span>\n<span class="line"><span style="color:#767676;">  ],</span></span>\n<span class="line"><span style="color:#767676;">})</span></span></code></pre></div><p>This pattern is useful for application flows such as approve-then-call, multi-step account setup, onboarding actions, and batched admin operations.</p><h2 id="sponsorship-flow" tabindex="-1">Sponsorship Flow <a class="header-anchor" href="#sponsorship-flow" aria-label="Permalink to &quot;Sponsorship Flow&quot;">​</a></h2><p>Sponsorship separates authorization from gas payment:</p><ol><li>The executor builds the transaction with <code>feePayerSignature</code> empty.</li><li>The executor signs the transaction intent using the <code>0x76</code> signature domain.</li><li>The application validates the intent against its sponsorship policy.</li><li>The sponsor signs the same intent using the <code>0x78</code> sponsor domain.</li><li>The final signed transaction is submitted with <code>eth_sendRawTransaction</code>.</li></ol><p>The sponsor signature binds to the executor address. A sponsor cannot reuse the same sponsor signature for a different executor.</p><p>For a user-facing application, the usual architecture is:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>User wallet / app client</span></span>\n<span class="line"><span>  signs executor intent</span></span>\n<span class="line"><span>        |</span></span>\n<span class="line"><span>        v</span></span>\n<span class="line"><span>Application sponsor service</span></span>\n<span class="line"><span>  checks policy and sponsor balance</span></span>\n<span class="line"><span>  adds feePayerSignature</span></span>\n<span class="line"><span>        |</span></span>\n<span class="line"><span>        v</span></span>\n<span class="line"><span>ev-reth JSON-RPC</span></span>\n<span class="line"><span>  eth_sendRawTransaction</span></span></code></pre></div><p>The sponsor pays gas up to <code>gasLimit * maxFeePerGas</code>. Any gas refund goes back to the sponsor. The executor only needs enough balance for value transfers in the batch.</p><h2 id="json-rpc-behavior" tabindex="-1">JSON-RPC Behavior <a class="header-anchor" href="#json-rpc-behavior" aria-label="Permalink to &quot;JSON-RPC Behavior&quot;">​</a></h2><p>Submit type <code>0x76</code> transactions with standard Ethereum JSON-RPC:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#767676;">{</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">jsonrpc</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">2.0</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">id</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">method</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">eth_sendRawTransaction</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">params</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> [</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">0x76...</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">]</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><p>When a sponsored transaction is returned by <code>eth_getTransactionByHash</code>, <code>eth_getBlockByNumber</code>, or related transaction APIs, ev-reth includes the recovered sponsor address as <code>feePayer</code>.</p><p>Receipts also include <code>feePayer</code> when sponsorship was used.</p><h2 id="validation" tabindex="-1">Validation <a class="header-anchor" href="#validation" aria-label="Permalink to &quot;Validation&quot;">​</a></h2><p>ev-reth validates type <code>0x76</code> transactions before admitting them to the txpool:</p><ul><li>The executor signature must be valid.</li><li>The sponsor signature must be valid when present.</li><li>The call list must be non-empty.</li><li>Only the first call may create a contract.</li><li>Sponsored transactions require the sponsor to have enough balance for gas.</li><li>Unsponsored transactions require the executor to have enough balance for gas and value.</li></ul><h2 id="client-support" tabindex="-1">Client Support <a class="header-anchor" href="#client-support" aria-label="Permalink to &quot;Client Support&quot;">​</a></h2><p>Most Ethereum wallets and CLIs do not know how to encode transaction type <code>0x76</code>. Use the JavaScript client for application code:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">pnpm</span><span style="color:#BFF3C2;"> add</span><span style="color:#BFF3C2;"> @evstack/evnode-viem</span><span style="color:#BFF3C2;"> viem</span></span></code></pre></div><p>See <a href="/ev-reth/js-client">JavaScript Client</a> for signing, batching, sponsorship, and serialization examples.</p>',40)])])}]]);export{o as __pageData,t as default};
